chart.options:
chart: {
  type: 'rangeBar',
  height: 350
},
title: {
  text: 'Monthly Temperature Range',
  align: 'left'
},
plotOptions: {
  bar: {
    horizontal: false
  }
},
dataLabels: {
  enabled: true
},
stroke: {
  width: 2,
  colors: ['#fff']
},
yaxis: {
  labels: {
    formatter: function (val) {
      return val + '°C'
    }
  }
}
